// ============================================
// PROCESSADOR DE EVENTOS YAMPI v3.5 (Revisão 04-03)
// ============================================

const inputJson = items[0].json;
const body = inputJson.body || {};
const resource = body.resource;

if (!resource) {
  return { json: { ignore: true, reason: "Dados insuficientes no payload (resource ausente)" } };
}

const customerData = resource.customer?.data || {}; 
const incomingEvent = body.event;
const statusAlias = resource.status?.data?.alias || 'unknown';
const paymentMethod = resource.payments?.[0]?.alias || resource.payment_method || 'unknown';

// 1. MAPEAMENTO DE EVENTOS
const EVENT_MAP = {
  "cart.reminder": "abandoned_cart",
  "cart.abandoned": "abandoned_cart",
  "order.created": "CHECK_PAYMENT_LOGIC",
  "order.paid": "purchase_approved",
  "payment.approved": "purchase_approved",
  "payment.pix_generated": "pix_generated",
  "order.shipped": "order_shipped",
  "payment.denied": "card_denied",
  "transaction.payment.refused": "card_denied"
};

// 2. CONFIGURAÇÃO DE VARIÁVEIS
const VARIABLE_CONFIG = {
  basic: {
    first_name: { path: 'customer.data.first_name', required: true },
    full_name: { path: 'customer.data.name', required: true },
    email: { path: 'customer.data.email', required: false }
  },
  checkout: {
    checkout_id: { path: 'id', required: true },
    url_carrinho: { path: 'checkout_url', required: false },
    url_carrinho_alt: { path: 'simulate_url', required: false },
    reorder_url: { path: 'reorder_url', required: false },
    valor_total: { path: 'value_total', required: false }
  },
  utm: {
    utm_source: { path: 'utm_source', required: false },
    utm_campaign: { path: 'utm_campaign', required: false },
    utm_medium: { path: 'utm_medium', required: false }
  },
  delivery: {
    tracking_public_url: { path: 'public_url', required: false },
    delivery_date: { path: 'date_delivery.date', required: false },
    address: { path: 'shipping_address.data.full_address', required: false },
  },
  pix: {
    pix_code: { 
      paths: ['pix.data.pix_qr_code', 'payments[0].metadata.data.pix_qr_code'],
      required: false 
    }
  },
  boleto: {
    boleto_url: { path: 'payments[0].boleto_url', required: false },
    linha_digitavel: { path: 'payments[0].boleto_code', required: false }
  },
  shipping: {
    tracking_code: { path: 'tracking_code', required: false },
    tracking_url: { path: 'tracking_url', required: false },
    // 🟢 MELHORIA: Captura de Bairro e Estado
    bairro: { path: 'shipping_address.data.neighborhood', required: false },
    estado: { path: 'shipping_address.data.state', required: false },
    address: { 
      custom: (res) => {
        const addr = res.shipping_address?.data;
        if (!addr) return null;

        // 🟢 MELHORIA: Identifica se o endereço é de uma Unidade de Retirada
        const isPickup = res.metadata?.data?.some(m => m.key === 'pickup_config_id' && m.value);
        const prefixo = isPickup ? "📍 [RETIRADA] " : "";

        return `${prefixo}${addr.street}, ${addr.number} - ${addr.city}/${addr.state} - CEP: ${addr.zipcode}`;
      }
    }
  }
};

// 3. FUNÇÕES AUXILIARES
function getNestedValue(obj, path) {
  if (!path) return null;
  return path.split('.').reduce((curr, key) => {
    const match = key.match(/^(\w+)\[(\d+)\]$/);
    if (match) return curr?.[match[1]]?.[parseInt(match[2])];
    return curr?.[key];
  }, obj);
}

function extractBySpec(resource, spec) {
  if (spec.custom) return spec.custom(resource);
  if (spec.paths) {
    for (const p of spec.paths) {
      const v = getNestedValue(resource, p);
      if (v) return v;
    }
    return null;
  }
  return getNestedValue(resource, spec.path) || null;
}

function extractVariables(resource, flowCode) {
  const vars = {};
  Object.entries(VARIABLE_CONFIG.basic).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));
  Object.entries(VARIABLE_CONFIG.checkout).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));
  Object.entries(VARIABLE_CONFIG.utm).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));
  Object.entries(VARIABLE_CONFIG.delivery).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));

  // 🟢 MELHORIA: Sempre tenta extrair dados de shipping (address, bairro, estado)
  // Isso garante que pedidos de qualquer fluxo tenham endereço completo
  Object.entries(VARIABLE_CONFIG.shipping).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));

  if (flowCode === 'pix_generated') {
    Object.entries(VARIABLE_CONFIG.pix).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));
  }
  if (flowCode === 'boleto_generated') {
    Object.entries(VARIABLE_CONFIG.boleto).forEach(([k, s]) => vars[k] = extractBySpec(resource, s));
  }

  try {
    const pUrl = resource.items?.data?.[0]?.sku?.data?.purchase_url;
    if (pUrl) vars.purchase_url = pUrl;
  } catch (e) {}

  if (resource.items && resource.items.data) {
    vars.lista_produtos = resource.items.data
      .map(item => `🔸 *${item.quantity}x ${item.sku?.data?.title || 'Produto'}*`)
      .join('\n');
  } else {
    vars.lista_produtos = "*Produtos não identificados*";
  }

  const AUTO_CAPTURE = [
    'discount_value', 'coupon_code', 'items_quantity', 
    'shipping_value', 'installments', 'payment_date',
    'track_code', 'track_url' 
  ];

  AUTO_CAPTURE.forEach(field => {
    if (resource[field] !== undefined && resource[field] !== null) {
      vars[field] = resource[field];
    }
  });

  return vars;
}

function tratarTelefone(rawPhone) {
  if (!rawPhone) return null;
  let nums = rawPhone.toString().replace(/\D/g, '');
  if (nums.startsWith('55')) nums = nums.substring(2);
  if (nums.length === 11) nums = nums.substring(0, 2) + nums.substring(3);
  return '55' + nums;
}

// 4. LÓGICA CENTRAL DE DECISÃO
let flowCode = EVENT_MAP[incomingEvent] || null;

if (incomingEvent === 'order.created' || flowCode === 'CHECK_PAYMENT_LOGIC') {
  if (['refused', 'cancelled'].includes(statusAlias)) {
    flowCode = (paymentMethod === 'credit_card') ? 'card_denied' : null;
  }
  else if (statusAlias === 'waiting_payment') {
    if (paymentMethod === 'pix') flowCode = 'pix_generated';
    else if (['billet', 'boleto'].includes(paymentMethod)) flowCode = 'boleto_generated';
    else flowCode = null;
  }
  else if (['paid', 'approved'].includes(statusAlias)) {
    flowCode = 'purchase_approved';
  }
} 
else if (incomingEvent === 'order.status.updated') {
  if (['on_carriage', 'shipped', 'delivered_transport'].includes(statusAlias)) {
    flowCode = 'order_shipped';
  } else {
    flowCode = null;
  }
}

// --- IMPLEMENTAÇÃO RETIRADA LOCAL ---
if (flowCode === 'purchase_approved' && resource.metadata && resource.metadata.data) {
  const isPickup = resource.metadata.data.find(meta => meta.key === 'pickup_config_id' && meta.value);
  if (isPickup) {
    flowCode = 'retirada_local';
  }
}

if (!flowCode) {
  return { json: { ignore: true, reason: `Status ignorado: ${statusAlias}` } };
}

const telefoneFinal = tratarTelefone(customerData.phone?.full_number || customerData.phone?.number);
let docNum = (customerData.cpf || customerData.cnpj || '').replace(/\D/g, '');

const contextData = extractVariables(resource, flowCode);

const output = {
    flow_code: flowCode,
    original_event: incomingEvent,
    phone: telefoneFinal,
    email: customerData.email,
    name: customerData.first_name,
    full_name: customerData.name,
    doc_number: docNum,
    checkout_id: resource.id,
    order_id: resource.id,
    total_value: resource.value_total,
    payment_method: paymentMethod,
    current_status: statusAlias,
    raw_payload: body
};

return {
  json: Object.assign(output, contextData) 
};

